```cpp
#include <TensorFlowLite.h>
#include <Wire.h>
#include <SparkFun_APDS9960.h>
#include "model.h"

// Error reporter for logging failures.
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Create an instance of the model
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version does not match.\nExpected %d but got %d\n", 
                         TFLITE_SCHEMA_VERSION, model->version());
}

// Define a buffer for tensor arena.
constexpr int kTensorArenaSize = 10240;
uint8_t tensor_arena[kTensorArenaSize];

// Build an interpreter to run the model with
tflite::ops::micro::AllOpsResolver resolver;

// Create an area of memory to use as an input to the model
TfLiteTensor* input_tensor;
TfLiteInterpreter* interpreter;

void setup() {
  // Start serial communication for debugging purposes
  Serial.begin(9600);

  // Initialize APDS-9960 (Color Sensor)
  if (!apds.init()) {
    Serial.println("Error initializing APDS-9960!");
    while (1);
  }
  apds.enableColor(true);

  // Build and allocate the interpreter
  tflite::MicroInterpreter static_interpreter(model, resolver, tensor_arena,
                                               kTensorArenaSize, error_reporter);
  interpreter = &static_interpreter;

  // Allocate memory from the tensor_arena for the model's tensors.
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed\n");
    return;
  }

  // Obtain pointers to the model's input and output tensors
  input_tensor = interpreter->input(0);
}

void loop() {
  uint16_t red, green, blue, clear;

  // Read color data from sensor
  if (!apds.getColorData(&red, &green, &blue, &clear)) {
    Serial.println("Error reading color data");
    return;
  }

  // Normalize the RGB values to [0.0, 1.0]
  float r = (float)red / 65535.0f;
  float g = (float)green / 65535.0f;
  float b = (float)blue / 65535.0f;

  // Copy the feature data into the input tensor
  float* input = interpreter->typed_input_tensor<float>(0);
  input[0] = r;
  input[1] = g;
  input[2] = b;

  // Run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    return;
  }

  // Obtain a pointer to the output tensor and process the results
  uint8_t* output = interpreter->typed_output_tensor<uint8_t>(0);
  int class_index = output[0];

  // Print the classification result using Unicode emojis
  switch (class_index) {
    case 0:
      Serial.println("Apple 🍏");
      break;
    case 1:
      Serial.println("Banana 🍌");
      break;
    case 2:
      Serial.println("Orange 🧡");
      break;
    default:
      Serial.println("Unknown Class ?");
      break;
  }

  delay(1000); // Delay for a second before the next reading
}
```

