tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Create an interpreter object
tflite::MicroInterpreter* interpreter = nullptr;

// Create the AllOpsResolver.
tflite::AllOpsResolver resolver;

// Declare global variables for sensor readings
SparkFun_APDS9960 apds;
uint16_t red, green, blue;

void setup() {
  Serial.begin(9600);

  // Initialize APDS-9960 (configure I2C and initial values)
  if (apds.init()) {
    Serial.println("APDS-9960 Initialization failed");
    while (1);
  }
  Serial.println("APDS-9960 sensor initialized");

  // Enable color sensing, with interrupt on threshold
  if (!apds.enableColorSensor(true)) {
    Serial.println("Failed to enable color sensor!");
    while (1);
  }

  // Load the model from flash and check for success
  const tflite::Model* model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    TF_LITE_REPORT_ERROR(error_reporter,
                         "Model provided is schema version %d not equal "
                         "to supported version %d.",
                         model->version(), TFLITE_SCHEMA_VERSION);
    while (1);
  }

  // Build an interpreter to run the model with no delegate
  static tflite::MicroInterpreter static_interpreter(
      model, resolver, tensor_arena, kTensorArenaSize, error_reporter);
  interpreter = &static_interpreter;

  // Allocate memory from the tensor arena for the model's tensors
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "AllocateTensors() failed");
    while (1);
  }

  // Ensure the input tensor has the proper dimensions and type
  TfLiteTensor* input = interpreter->input(0);
  if ((input->dims->size != 2) || (input->dims->data[0] != 1) ||
      (input->dims->data[1] != 3) || (input->type != kTfLiteFloat32)) {
    TF_LITE_REPORT_ERROR(error_reporter, "Bad input tensor parameters");
    while (1);
  }
}

void loop() {
  // Check if color data is available
  if (!apds.colorDataReady()) return;

  // Get the red, green, and blue color values
  apds.getColorData(&red, &green, &blue);

