```cpp
#include <TensorFlowLite.h>
#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "model.h"

// Phase 1: Initialization

// Error Reporter
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Model and Interpreter
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model provided is schema version %d not equal to supported version %d.",
                         model->version(), TFLITE_SCHEMA_VERSION);
}

// Op Resolver
tflite::ops::micro::AllOpsResolver resolver;

// Tensor Arena
uint8_t tensor_arena[2048];

// Interpreter
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, sizeof(tensor_arena), error_reporter);

// Allocate Memory
TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed");
}

// Input Tensor Details
TfLiteTensor* input = interpreter.input(0);
if ((input->dims->size != 2) || (input->dims->data[1] != 3)) {
  error_reporter->Report("Bad input tensor dimensions! Expected %d,%d, got %d,%d:%d",
                         1, 3, input->dims->size, input->dims->data[0], input->dims->data[1]);
}

// Color Sensor
Adafruit_APDS9960 apds;

// Phase 2: Preprocessing

void setup() {
  Serial.begin(9600);

  // Initialize APDS-9960 (gesture sensor)
  if (!apds.init()) {
    Serial.println("No APDS-9960 found");
    while (1) { delay(10); }
  }

  // Enable color module
  apds.enableColor(true);

  // Start running the model
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed on input!");
  }
}

void loop() {
  uint16_t r, g, b, c;
  apds.getColorData(&r, &g, &b, &c);

  // Normalize color values to float in range [0, 1]
  float red = static_cast<float>(r) / c;
  float green = static_cast<float>(g) / c;
  float blue = static_cast<float>(b) / c;

  // Copy data into the model's input tensor buffer
  float* input_data = interpreter.input(0)->data.f;
  input_data[0] = red;
  input_data[1] = green;
  input_data[2] = blue;

  // Invoke the interpreter
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed on input!");
  }

  // Read the output tensor
  uint8_t* output_data = interpreter.output(0)->data.uint8;
  int predicted_class = static_cast<int>(output_data[0]);

  // Map prediction to class name and print using Unicode emoji
  switch (predicted_class) {
    case 0: Serial.println("Apple \xF0\x9F\x8D\x8E"); break;  // Apple
    case 1: Serial.println("Banana \xF0\x9F\x8C\x8A"); break; // Banana
    case 2: Serial.println("Orange \xF0\x9F\x8C\x85"); break; // Orange
    default: Serial.println("Unknown Class");
  }

  delay(1000); // Delay between readings
}
```

