```cpp
#include <TensorFlowLite.h>
#include <Wire.h>
#include <Adafruit_APDS9960.h>

#include "model.h"

// Initialize the APDS-9960 sensor
Adafruit_APDS9960 apds;

// Declare TensorFlow Lite Micro variables
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version does not match interpreter!");
}

// Define tensor arena size and allocate memory
constexpr int kTensorArenaSize = 2048;
uint8_t tensor_arena[kTensorArenaSize];

// Create an interpreter to run the model with MicroAllocator
tflite::MicroInterpreter* interpreter;

// Declare OpResolver: must be a global object due to C API requirements
tflite::AllOpsResolver resolver;

// Input/output tensor handles
TfLiteTensor* input;
TfLiteTensor* output;

void setup() {
  Serial.begin(9600);

  // Initialize the sensor
  if (!apds.init()) {
    error_reporter->Report("Failed to initialize APDS-9960 sensor!");
    while (1);
  }

  // Set up the light sensor for RGB data
  apds.enableColor(true);

  // Build and allocate tensors, and check for errors
  interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena,
                                               kTensorArenaSize, error_reporter);

  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed");
    while (1);
  }

  // Obtain pointers to the model's input and output tensors
  input = interpreter->input(0);
  output = interpreter->output(0);

  // Verify tensor details are as expected
  if ((input->dims->size != 2) || (input->dims->data[0] != 1) || (input->dims->data[1] != 3)) {
    error_reporter->Report("Bad input tensor dimensions!");
    while (1);
  }

  if ((output->dims->size != 1) || (output->dims->data[0] != 1)) {
    error_reporter->Report("Bad output tensor dimensions!");
    while (1);
  }
}

void loop() {
  // Read RGB values from the sensor
  uint16_t r, g, b;
  apds.getColorData(&r, &g, &b);

  // Normalize RGB values to [0.0, 1.0]
  float red = static_cast<float>(r) / 1023.0f;
  float green = static_cast<float>(g) / 1023.0f;
  float blue = static_cast<float>(b) / 1023.0f;

  // Copy normalized RGB values to input tensor
  input->data.f[0] = red;
  input->data.f[1] = green;
  input->data.f[2] = blue;

  // Run the inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed!");
    while (1);
  }

  // Process output tensor and print corresponding class emoji
  uint8_t predicted_class = output->data.uint8[0];
  switch(predicted_class) {
    case 0:
      Serial.println("🍎");  // Apple
      break;
    case 1:
      Serial.println("🍌");  // Banana
      break;
    case 2:
      Serial.println("🍊");  // Orange
      break;
    default:
      Serial.println("Unknown");
  }

  // Delay before the next reading
  delay(500);
}
