#include <TensorFlowLite.h>
#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "model.h"

// Error reporter for logging
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Define the model and interpreter
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  TF_LITE_REPORT_ERROR(error_reporter,
                       "Model provided is schema version %d not equal "
                       "to supported version %d.",
                       model->version(), TFLITE_SCHEMA_VERSION);
  return;
}

// Define the tensor arena
uint8_t tensor_arena[8000];

// Create an interpreter to run the model with micro runtime
tflite::MicroInterpreter static_interpreter(model, resolver, tensor_arena, sizeof(tensor_arena), error_reporter);

// Allocate memory from the tensor arena for the model's tensors
TfLiteStatus allocate_status = static_interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  TF_LITE_REPORT_ERROR(error_reporter, "AllocateTensors() failed");
  return;
}

// Get pointers to input and output tensors
TfLiteTensor* input = static_interpreter.input(0);
TfLiteTensor* output = static_interpreter.output(0);

// Initialize the APDS9960 sensor
Adafruit_APDS9960 apds;

void setup() {
  Serial.begin(9600);

  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS-9960! Exiting...");
    while (1);
  }

  // Configure the sensor
  apds.enableColor(true);
}

void loop() {
  uint16_t r, g, b, c;
  apds.getColorData(&r, &g, &b, &c);

  // Normalize RGB values to [0, 1]
  float red = (float)r / 1023.0f;
  float green = (float)g / 1023.0f;
  float blue = (float)b / 1023.0f;

  // Set the input tensor data
  input->data.f[0] = red;
  input->data.f[1] = green;
  input->data.f[2] = blue;

  // Run inference
  TfLiteStatus invoke_status = static_interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Invoke failed on index %d\n", i);
    return;
  }

  // Process the output tensor data
  uint8_t class_index = output->data.uint8[0];

  // Output the result using Unicode emojis
  switch (class_index) {
    case 0:
      Serial.println("🍎");  // Apple
      break;
    case 1:
      Serial.println("🍌");  // Banana
      break;
    case 2:
      Serial.println("🍊");  // Orange
      break;
    default:
      Serial.println("Unknown");
      break;
  }

  delay(1000);  // Delay between readings
}
