   input_tensor = interpreter.input(0);
   if ((input_tensor == nullptr) || (input_tensor->dims->size != 1)) {
     error_reporter->Report("Error: Model input should be a 1-D tensor!");
     while (1);
   }
 }

 void loop() {
   uint16_t r, g, b, c;
   apds.getColorData(&r, &g, &b, &c);

   // Normalize the RGB values to float32 in range [0.0, 1.0]
   input_tensor->data.f[0] = static_cast<float>(r) / 65535.0f;
   input_tensor->data.f[1] = static_cast<float>(g) / 65535.0f;
   input_tensor->data.f[2] = static_cast<float>(b) / 65535.0f;

   // Run inference
   TfLiteStatus invoke_status = interpreter.Invoke();
   if (invoke_status != kTfLiteOk) {
     error_reporter->Report("Invoke failed!\n");
   }

   // Get the output tensor and classify object
   TfLiteTensor* output_tensor = interpreter.output(0);
   uint8_t class_index = output_tensor->data.uint8[0];

   // Map index to Unicode emoji for classification result
   const char* emoji;
   switch (class_index) {
     case 0:
       emoji = "\U0001F34E"; // Apple 🍎
       break;
     case 1:
       emoji = "\U0001F34C"; // Banana 🍌
       break;
     case 2:
       emoji = "\U0001F34A"; // Orange 🍊
       break;
     default:
       emoji = "?";
   }

   Serial.print("Detected object: ");
   Serial.println(emoji);
   delay(1000);
 }
