// Load the TensorFlow Lite model
extern const unsigned char model[];
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

constexpr int kTensorArenaSize = 8000;
uint8_t tensor_arena[kTensorArenaSize];

// Define the model pointer and interpreter
const tflite::Model* model_ptr = tflite::GetModel(model);
if (model_ptr->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version (%d) not supported\n", model_ptr->version());
}

tflite::AllOpsResolver resolver;
tflite::MicroInterpreter interpreter(model_ptr, resolver, tensor_arena, kTensorArenaSize, error_reporter);

// Allocate memory for tensors
TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed\n");
}

// Define model inputs
TfLiteTensor* input_tensor = interpreter.input(0);
if ((input_tensor == nullptr) || (input_tensor->dims->size != 1) || (input_tensor->dims->data[0] != 3)) {
  error_reporter->Report("Bad input tensor\n");
}

// Define model outputs
TfLiteTensor* output_tensor = interpreter.output(0);
if ((output_tensor == nullptr) || (output_tensor->dims->size != 1) || (output_tensor->dims->data[0] != 1)) {
  error_reporter->Report("Bad output tensor\n");
}

// Initialize the sensor
Adafruit_APDS9960 apds;
apds.init();
apds.enableColor(true);

void setup() {
  Serial.begin(9600);
}

void loop() {
  uint16_t r, g, b, c;

  if (!apds.getColor(&r, &g, &b, &c)) {
    error_reporter->Report("Failed to read color data\n");
    return;
  }

  // Normalize the color values
  float red = static_cast<float>(r) / 4095.0f;
  float green = static_cast<float>(g) / 4095.0f;
  float blue = static_cast<float>(b) / 4095.0f;

  // Copy the processed data into the model's input tensor
  input_tensor->data.f[0] = red;
  input_tensor->data.f[1] = green;
  input_tensor->data.f[2] = blue;

  // Run the inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    return;
  }

  // Process the output tensor
  uint8_t predicted_class = output_tensor->data.uint8[0];

  // Execute application behavior based on inference result
  switch (predicted_class) {
    case 0:
      Serial.println("Apple \uF8FF"); // Apple emoji
      break;
    case 1:
      Serial.println("Banana \uD83C\uDF4C"); // Banana emoji
      break;
    case 2:
      Serial.println("Orange \uD83C\uDF4A"); // Orange emoji
      break;
    default:
      Serial.println("Unknown");
      break;
  }

  delay(1000);
}
