#include <Wire.h>
#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/micro/micro_error_reporter.h>
#include <tensorflow/lite/micro/micro_interpreter.h>
#include "Adafruit_APDS9960.h"
#include "model.h"

// Create an area of memory to use for input, output, and intermediate arrays.
constexpr int kTensorArenaSize = 8000;
uint8_t tensor_arena[kTensorArenaSize];

// Create an error reporter object
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Create the model and interpreter
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version does not match expected version %d.\n", TFLITE_SCHEMA_VERSION);
}

tflite::ops::micro::AllOpsResolver resolver;

// Build an interpreter to run the model with
static tflite::MicroInterpreter static_interpreter(
    model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

tflite::MicroInterpreter* interpreter = &static_interpreter;

// Allocate memory from the tensor_arena for the model's tensors.
TfLiteStatus allocate_status = interpreter->AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed\n");
}

// Obtain pointers to the model's input and output tensors.
TfLiteTensor* input = interpreter->input(0);
TfLiteTensor* output = interpreter->output(0);

Adafruit_APDS9960 apds;

void setup() {
  Serial.begin(9600);

  if (!apds.init()) {
    Serial.println("APDS-9960 initialization failed");
    while (1);
  }
  apds.enableColor(true);
}

void loop() {
  uint16_t r, g, b, c;
  apds.getColorData(&r, &g, &b, &c);

  // Normalize the RGB values
  float sum = r + g + b;
  if (sum != 0) {
    input->data.f[0] = static_cast<float>(r) / sum;
    input->data.f[1] = static_cast<float>(g) / sum;
    input->data.f[2] = static_cast<float>(b) / sum;
  } else {
    input->data.f[0] = 0.0f;
    input->data.f[1] = 0.0f;
    input->data.f[2] = 0.0f;
  }

  // Run the inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
  }

  // Process the output
  int predicted_class = static_cast<int>(output->data.uint8[0]);

  switch (predicted_class) {
    case 0:
      Serial.println("Apple");
      break;
    case 1:
      Serial.println("Banana");
      break;
    case 2:
      Serial.println("Orange");
      break;
    default:
      Serial.println("Unknown class");
      break;
  }

  delay(1000); // Delay between readings
}
