```cpp
#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/micro/micro_error_reporter.h>
#include <tensorflow/lite/micro/micro_interpreter.h>
#include <Wire.h>
#include <Adafruit_APDS9960.h>

// Include the model header file
#include "model.h"

// Define the tensor arena size (as specified in application specifications)
#define TENSOR_ARENA_SIZE (4 * 1024)

// Declare variables for TensorFlow Lite Micro
tflite::MicroErrorReporter micro_error_reporter;
tflite::AllOpsResolver resolver;
const tflite::Model* model = tflite::GetModel(g_model);
uint8_t tensor_arena[TENSOR_ARENA_SIZE];
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, TENSOR_ARENA_SIZE, &micro_error_reporter);

// Declare variables for sensor readings
Adafruit_APDS9960 apds = Adafruit_APDS9960();

// Function to normalize the RGB values based on dataset statistics
void normalizeRGB(float* r, float* g, float* b) {
    *r = (*r - 0.5623661971830984) / 0.028464634416673053;
    *g = (*g - 0.23716901408450702) / 0.021283115987959598;
    *b = (*b - 0.200056338028169) / 0.019259793296579324;
}

void setup() {
  // Initialize Serial communication
  Serial.begin(9600);

  // Initialize the APDS-9960 sensor
  if (!apds.begin()) {
    Serial.println("APDS-9960 initialization failed");
    while (1);
  }
  apds.enableColor(true);

  // Load and allocate memory for the model
  interpreter.AllocateTensors();

  // Ensure input tensor is valid
  tflite::Tensor* input = interpreter.input(0);
  if ((input->dims->size != 2) || (input->dims->data[1] != 3)) {
    Serial.println("Input tensor has unexpected dimensions");
    while (1);
  }
}

void loop() {
  // Check if color data is ready
  if (!apds.colorDataReady()) {
    return;
  }

  uint16_t r, g, b, c;
  apds.getColorData(&r, &g, &b, &c);

  // Normalize RGB values based on dataset statistics
  float normR = (float)r / 255.0f;
  float normG = (float)g / 255.0f;
  float normB = (float)b / 255.0f;

  normalizeRGB(&normR, &normG, &normB);

  // Load normalized RGB values into the input tensor
  tflite::Tensor* input = interpreter.input(0);
  input->data.f[0] = normR;
  input->data.f[1] = normG;
  input->data.f[2] = normB;

  // Run inference
  if (interpreter.Invoke() != kTfLiteOk) {
    Serial.println("Invoke failed");
    return;
  }

  // Read the output tensor
  tflite::Tensor* output = interpreter.output(0);
  uint8_t predictedClass = static_cast<uint8_t>(output->data.uint8[0]);

  // Map the predicted class to the corresponding emoji and print it
  switch (predictedClass) {
    case 0:
      Serial.print("Apple \U0001F34E\n");  // Apple emoji
      break;
    case 1:
      Serial.print("Banana \U0001F34C\n");  // Banana emoji
      break;
    case 2:
      Serial.print("Orange \U0001F34A\n");  // Orange emoji
      break;
    default:
      Serial.println("Unknown class");
      break;
  }

  // Add a delay to avoid flooding the serial output
  delay(500);
}
