```cpp
#include <Arduino.h>
#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "model.h"
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "tensorflow/lite/version.h"

// Declare the TensorFlow Lite Micro components
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  TF_LITE_REPORT_ERROR(error_reporter,
                       "Model provided is schema version %d not equal "
                       "to supported version %d.",
                       model->version(), TFLITE_SCHEMA_VERSION);
  return;
}

tflite::AllOpsResolver resolver;

const int tensor_arena_size = 6000;
uint8_t tensor_arena[tensor_arena_size];

tflite::MicroInterpreter interpreter(model, resolver, tensor_arena,
                                      tensor_arena_size, error_reporter);

// Initialize the APDS9960 color sensor
Adafruit_APDS9960 apds;

void setup() {
  Serial.begin(9600);

  // Initialize the TensorFlow Lite Micro components
  if (interpreter.AllocateTensors() != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "AllocateTensors() failed");
    return;
  }

  // Set up APDS9960 color sensor
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS9960 sensor! Exiting...");
    while (1);
  }
  apds.enableColor(true);

  delay(250); // Let the sensor settle

  Serial.println("APDS9960 color sensor initialized successfully");
}

void loop() {
  if (!apds.colorAvailable()) {
    return;
  }

  uint16_t r, g, b, c;

  apds.getColorData(&r, &g, &b, &c);

  // Normalize the RGB values to [0, 1]
  float red = static_cast<float>(r) / 65535.0;
  float green = static_cast<float>(g) / 65535.0;
  float blue = static_cast<float>(b) / 65535.0;

  // Get pointer to the model's input tensor
  float* input = interpreter.input(0)->data.f;

  // Copy RGB values into the model's input tensor
  input[0] = red;
  input[1] = green;
  input[2] = blue;

  // Run inference on the model
  if (interpreter.Invoke() != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Invoke failed");
    return;
  }

  // Get pointer to the model's output tensor
  const uint8_t* output = interpreter.output(0)->data.uint8;

  // Determine the class based on the output tensor
  switch (output[0]) {
    case 0:
      Serial.println("Apple 🍏");
      break;
    case 1:
      Serial.println("Banana 🍌");
      break;
    case 2:
      Serial.println("Orange 🍊");
      break;
    default:
      Serial.println("Unknown class");
      break;
  }

  delay(500); // Delay between readings
}
