  if (!apds.begin()) {
    error_reporter->Report("Failed to initialize APDS9960\n");
    while (1);
  }

  // Enable color sensor
  apds.enableColor(true);
}

void loop() {
  // Wait for new color data
  if (!apds.colorDataReady()) {
    delay(25);
    return;
