  // Read the color values
  uint16_t r, g, b, c;
  apds.getColorData(&r, &g, &b, &c);

  // Normalize RGB values to [0, 1]
  float red = (float)r / 1024.0f;
  float green = (float)g / 1024.0f;
  float blue = (float)b / 1024.0f;

  // Copy normalized RGB values to input tensor
  input_tensor->data.f[0] = red;
  input_tensor->data.f[1] = green;
  input_tensor->data.f[2] = blue;

  // Run the inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    return;
  }

  // Get output tensor pointer
  TfLiteTensor* output_tensor = interpreter.output(0);
  uint8_t predicted_class = output_tensor->data.uint8[0];

  // Map the predicted class to an emoji and print it
