// Define the tensor arena size
constexpr int kTensorArenaSize = 10240;
uint8_t tensor_arena[kTensorArenaSize];

// Create an error reporter instance
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Create the model instance from the header file
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version (%d) not supported. Expected %d.",
                         model->version(), TFLITE_SCHEMA_VERSION);
}

// Create an OpResolver to resolve the operations in the model
tflite::ops::micro::AllOpsResolver resolver;

// Build and initialize the interpreter with the model, resolver, and tensor arena
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

// Allocate memory for tensors
TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed");
}

// Get pointers to the model's input and output buffers
float* input_buffer = interpreter.input(0)->data.f;
uint8_t* output_buffer = interpreter.output(0)->data.uint8;

// Initialize the APDS9960 color sensor
Adafruit_APDS9960 apds;

void setup() {
  Serial.begin(9600);
  while (!Serial) delay(10); // Wait for serial port to connect (useful for native USB port only)

  if (!apds.begin()) {
    error_reporter->Report("Failed to initialize APDS9960 sensor");
    while (1) delay(10);
  }

  apds.enableColor(true);

  // Check the model validity
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    error_reporter->Report(
      "Model schema version (%d) not supported. Expected %d.",
      model->version(), TFLITE_SCHEMA_VERSION);
  }

  // Allocate tensors and check for errors
  TfLiteStatus allocate_status = interpreter.AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed");
    while (1) delay(10);
  }
}

void loop() {
  // Read color values from the sensor
  uint16_t red, green, blue;
  apds.getColor(&red, &green, &blue);

  // Normalize RGB values to [0.0, 1.0]
  float norm_red = static_cast<float>(red) / 1023.0f;
  float norm_green = static_cast<float>(green) / 1023.0f;
  float norm_blue = static_cast<float>(blue) / 1023.0f;

  // Copy normalized RGB values to the input tensor
  input_buffer[0] = norm_red;
  input_buffer[1] = norm_green;
  input_buffer[2] = norm_blue;

  // Run the inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed");
    return;
  }

  // Process the output tensor
  uint8_t predicted_class = output_buffer[0];

  // Output the classification result with Unicode emojis
  switch (predicted_class) {
    case 0:
      Serial.println("Apple 🍏");
      break;
    case 1:
      Serial.println("Banana 🍌");
      break;
    case 2:
      Serial.println("Orange 🍊");
      break;
    default:
      Serial.println("Unknown Class");
      break;
  }

  delay(500); // Delay between readings
}
