#include <TensorFlowLite.h>
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/system_setup.h"

// Model includes
#include "./model.h"  // Ensure this file is correctly placed and named

// Sensor library
#include <Wire.h>
#include <Adafruit_APDS9960.h>

// Define the size of the tensor arena (adjust as necessary)
#define TENSOR_ARENA_SIZE (2048)

// Create an error reporter instance
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Declare global variables for TensorFlow Lite Micro
const tflite::Model* model = nullptr;
tflite::AllOpsResolver resolver;
uint8_t tensor_arena[TENSOR_ARENA_SIZE];
tflite::MicroInterpreter* interpreter = nullptr;

// Define input and output pointers
float* input_buffer;
uint8_t* output_buffer;

// Adafruit APDS9960 sensor instance
Adafruit_APDS9960 apds;

void setup() {
  // Initialize serial communication for debugging
  Serial.begin(9600);

  // Initialize the model
  tflite::InitializeTarget();
  model = tflite::GetModel(g_model);  // Assuming g_model is defined in model.h

  if (model->version() != TFLITE_SCHEMA_VERSION) {
    error_reporter->Report("Error: Model schema version does not match\nExpected %d but found %d\n", 
                            TFLITE_SCHEMA_VERSION, model->version());
    return;
  }

  // Build the interpreter
  static tflite::MicroInterpreter static_interpreter(model, resolver, tensor_arena, TENSOR_ARENA_SIZE, error_reporter);
  interpreter = &static_interpreter;

  // Allocate memory for tensors
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    error_reporter->Report("Error: AllocateTensors() failed\n");
    return;
  }

  // Get pointers to the model's input and output buffers
  input_buffer = interpreter->input(0)->data.f;
  output_buffer = interpreter->output(0)->data.uint8;

  // Initialize the APDS9960 sensor
  if (!apds.begin()) {
    Serial.println("Error: Failed to initialize APDS9960 sensor!");
    while (1);
  }

  // Enable color sensor
  apds.enableColor(true);

  // Set default integration time and gain
  apds.setIntegrationTime(APDS9960_INTEGRATIONTIME_50MS);
  apds.setGain(APDS9960_GAIN_4X);

  Serial.println("Setup complete!");
}

void loop() {
  uint16_t r, g, b;

  // Read color data from the sensor
  if (apds.colorAvailable()) {
    apds.getColorData(&r, &g, &b);

    // Normalize RGB values to [0.0, 1.0] range based on your dataset's scale
    float red = r / 65535.0f;
    float green = g / 65535.0f;
    float blue = b / 65535.0f;

    // Copy normalized color data to the model's input tensor buffer
    input_buffer[0] = red;
    input_buffer[1] = green;
    input_buffer[2] = blue;

    // Run inference
    TfLiteStatus invoke_status = interpreter->Invoke();
    if (invoke_status != kTfLiteOk) {
      error_reporter->Report("Error: Invoke() failed\n");
      return;
    }

    // Get the predicted class from the output tensor buffer
    uint8_t predicted_class = output_buffer[0];

    // Map predicted class to object name and print using Unicode emojis
    switch (predicted_class) {
      case 0:
        Serial.println("Apple 🍏");
        break;
      case 1:
        Serial.println("Banana 🍌");
        break;
      case 2:
        Serial.println("Orange 🍊");
        break;
      default:
        Serial.println("Unknown object");
        break;
    }

    // Delay before the next reading
    delay(500);
  }
}
