#include <Arduino.h>
#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include <TensorFlowLite.h>
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "model.h" // Include your model header file here

// Define the tensor arena size
#define TENSOR_ARENA_SIZE (2048)

// Create an area of memory to use for input, output, and intermediate arrays.
static uint8_t tensor_arena[TENSOR_ARENA_SIZE];

// Set up the error reporter
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Create an instance of the APDS9960 sensor
Adafruit_APDS9960 apds;

// Declare variables for model input and output
float input_data[3]; // [Red, Green, Blue]
uint8_t output_data[1];

// Load the model from Flash into memory
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version has changed! Please regenerate your binary model file.");
}

// Pull in all the operations for the interpreter.
tflite::AllOpsResolver resolver;

// Build an interpreter to run the model
static tflite::MicroInterpreter static_interpreter(
    model, resolver, tensor_arena, TENSOR_ARENA_SIZE, error_reporter);
tflite::MicroInterpreter* interpreter = &static_interpreter;

// Allocate memory from the tensor_arena for the model's tensors
TfLiteStatus allocate_status = interpreter->AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed");
}

// Get pointers to input and output tensors
TfLiteTensor* input = interpreter->input(0);
TfLiteTensor* output = interpreter->output(0);

void setup() {
  // Start serial communication for debugging purposes
  Serial.begin(9600);

  // Initialize the APDS-9960 (light-to-digital converter with I2C interface)
  if (!apds.begin()) {
    error_reporter->Report("Failed to initialize APDS-9960!");
    while (1);
  }

  // Enable color sensor
  apds.enableColor(true);

  // Set interrupt pin as input
  pinMode(4, INPUT);

  // Wait for initialization to complete
  delay(1000);

  // Print a message indicating setup is complete
  Serial.println("Setup completed successfully!");
}

void loop() {
  uint16_t r = 0, g = 0, b = 0;

  if (apds.colorAvailable()) {
    apds.getColorData(&r, &g, &b);

    // Normalize RGB values to the range [0.0, 1.0]
    input_data[0] = static_cast<float>(r) / 65535.0f;
    input_data[1] = static_cast<float>(g) / 65535.0f;
    input_data[2] = static_cast<float>(b) / 65535.0f;

    // Copy the normalized RGB values to the model's input tensor
    memcpy(input->data.f, input_data, sizeof(float) * 3);

    // Run inference on the model
    TfLiteStatus invoke_status = interpreter->Invoke();
    if (invoke_status != kTfLiteOk) {
      error_reporter->Report("Invoke failed!");
    }

    // Get the output from the model's output tensor
    uint8_t class_index = output_data[0] = *output->data.uint8;

    // Map the output to a Unicode emoji representing the predicted class
    switch (class_index) {
      case 0:
        Serial.println("Apple 🍏");
        break;
      case 1:
        Serial.println("Banana 🍌");
        break;
      case 2:
        Serial.println("Orange 🍊");
        break;
      default:
        Serial.println("Unknown object");
        break;
    }

    // Add a delay between readings
    delay(500);
  }
}
