uint8_t output[1];

void setup() {
  // Start serial communication
  Serial.begin(9600);

  // Initialize the APDS-9960 sensor
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS-9960 sensor!");
    while (1);
  }

  apds.enableColor(true);

  // Register model operators
  tflite::AllOpsResolver resolver;

  // Instantiate the interpreter
  interpreter = new tflite::MicroInterpreter(g_model, resolver, tensor_arena,
                                              tensor_arena_size, error_reporter);

  // Allocate tensors
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    while (1);
  }

  // Get input and output tensor pointers
  TfLiteTensor* input_tensor = interpreter->input(0);
  TfLiteTensor* output_tensor = interpreter->output(0);

  if ((input_tensor == nullptr) || (output_tensor == nullptr)) {
    Serial.println("Failed to obtain tensor pointers!");
    while (1);
  }

  // Ensure the input and output tensors have expected dimensions
  if ((input_tensor->dims->size != 2) || (input_tensor->dims->data[0] != 1) || (input_tensor->dims->data[1] != 3)) {
    Serial.println("Unexpected input tensor shape!");
    while (1);
  }

  if ((output_tensor->dims->size != 2) || (output_tensor->dims->data[0] != 1) || (output_tensor->dims->data[1] != 1)) {
    Serial.println("Unexpected output tensor shape!");
    while (1);
  }
}

void loop() {
  uint16_t r, g, b, c;

  // Read color data from the APDS-9960 sensor
  if (!apds.colorAvailable()) {
    delay(50);
    return;
  }

  apds.getColorData(&r, &g, &b, &c);

  // Normalize RGB values to [0, 1] range
  input[0] = r / 65535.0f;  // Red
  input[1] = g / 65535.0f;  // Green
  input[2] = b / 65535.0f;  // Blue

  // Copy the input data to the model's input tensor buffer
  TfLiteTensor* input_tensor = interpreter->input(0);
  for (int i = 0; i < 3; ++i) {
    input_tensor->data.f[i] = input[i];
  }

  // Run inference
  if (interpreter->Invoke() != kTfLiteOk) {
    Serial.println("Inference failed!");
    return;
  }

  // Read the output from the model's output tensor buffer
  TfLiteTensor* output_tensor = interpreter->output(0);
  uint8_t predicted_class = output_tensor->data.uint8[0];

  // Map the predicted class to a Unicode emoji and print it
  switch (predicted_class) {
    case 0:
      Serial.println("Apple 🍏");
      break;
    case 1:
      Serial.println("Banana 🍌");
      break;
    case 2:
      Serial.println("Orange 🍊");
      break;
    default:
      Serial.println("Unknown class");
      break;
  }

  delay(500);  // Wait for a short period before the next reading
}
