#include <TensorFlowLite.h>
#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "model.h"

// Initialize the sensor
Adafruit_APDS9960 apds;

// TensorFlow Lite globals
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version does not match TFLite Schema version.\n");
}

tflite::ops::micro::AllOpsResolver resolver;

uint8_t tensor_arena[2048];
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, sizeof(tensor_arena), error_reporter);

TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed\n");
}

// Get input and output tensors
TfLiteTensor* input = interpreter.input(0);
TfLiteTensor* output = interpreter.output(0);

void setup() {
  Serial.begin(9600);

  // Initialize the sensor
  if (!apds.begin()) {
    error_reporter->Report("APDS-9960 not found\n");
    while (1);
  }

  apds.enableColor(true);

  // Allocate tensors
  if (allocate_status != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed\n");
    while (1);
  }
}

void loop() {
  uint16_t r, g, b, c;
  apds.getColorData(&r, &g, &b, &c);

  // Normalize RGB values to [0.0, 1.0]
  float red = r / 65535.0f;
  float green = g / 65535.0f;
  float blue = b / 65535.0f;

  // Copy normalized RGB values to input tensor
  input->data.f[0] = red;
  input->data.f[1] = green;
  input->data.f[2] = blue;

  // Run the inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    while (1);
  }

  // Process output tensor
  uint8_t predicted_class = output->data.uint8[0];

  // Map the class index to a Unicode emoji and print it
  const char* emojis[] = {"\xF0\x9F\x8C\x8E", "\xF0\x9F\x8D\x8C", "\xF0\x9F\x8C\x85"};
  Serial.print(emojis[predicted_class]);
  Serial.println();

  delay(1000); // Delay for a second before the next reading
}
```

