```cpp
#include <TensorFlowLite.h>
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"

#include <Wire.h>
#include <Adafruit_APDS9960.h>

// Include the model header file
#include "./model.h"

// Error Reporter
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Tensor Arena
const int tensor_arena_size = 2048;
uint8_t tensor_arena[tensor_arena_size];

// Model and Interpreter
const tflite::Model* model = tflite::GetModel(g_model);
tflite::AllOpsResolver resolver;
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, tensor_arena_size, error_reporter);

// Input/Output Tensors
TfLiteTensor* input_tensor;
TfLiteTensor* output_tensor;

// Color Sensor
Adafruit_APDS9960 apds;

void setup() {
  // Initialize Serial Communication
  Serial.begin(9600);
  while (!Serial) delay(10);

  // Initialize Tensor Arena and Interpreter
  if (interpreter.AllocateTensors() != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed");
    return;
  }

  // Get Input/Output Tensors
  input_tensor = interpreter.input(0);
  output_tensor = interpreter.output(0);

  // Initialize Color Sensor
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS9960 sensor!");
    while (1) delay(10);
  }

  // Configure Color Sensor
  apds.enableColor(true);
}

void loop() {
  uint16_t red, green, blue;

  // Read color values from the sensor
  if (apds.colorAvailable()) {
    apds.getColorData(&red, &green, &blue);

    // Normalize RGB values to [0, 1]
    float normalized_red = static_cast<float>(red) / 65535.0;
    float normalized_green = static_cast<float>(green) / 65535.0;
    float normalized_blue = static_cast<float>(blue) / 65535.0;

    // Fill input tensor
    input_tensor->data.f[0] = normalized_red;
    input_tensor->data.f[1] = normalized_green;
    input_tensor->data.f[2] = normalized_blue;

    // Run inference
    if (interpreter.Invoke() != kTfLiteOk) {
      error_reporter->Report("Invoke failed");
      return;
    }

    // Process output tensor
    uint8_t predicted_class = output_tensor->data.uint8[0];
    const char* class_label = "";

    switch (predicted_class) {
      case 0:
        class_label = "Apple 🍏";
        break;
      case 1:
        class_label = "Banana 🍌";
        break;
      case 2:
        class_label = "Orange 🍊";
        break;
      default:
        class_label = "Unknown";
    }

    // Output result
    Serial.print("Predicted Class: ");
    Serial.println(class_label);
  }
}
