  apds.enableColor(true);
  apds.setIntegrationTime(APDS9960_INTEGRATIONTIME_25MS);
  apds.setColorGain(APDS9960_GAIN_4X);

  // Allocate memory for tensors
  if (allocate_status != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed");
  }
}

void loop() {
  uint16_t red, green, blue, clear;

  // Read color data from the sensor
  apds.getColorData(&red, &green, &blue, &clear);

  // Normalize values to [0.0, 1.0] range (assuming max value is 255)
  float normalized_red = static_cast<float>(red) / 255.0f;
  float normalized_green = static_cast<float>(green) / 255.0f;
  float normalized_blue = static_cast<float>(blue) / 255.0f;

  // Assign the sensor values to the input tensor
  input->data.f[0] = normalized_red;
  input->data.f[1] = normalized_green;
  input->data.f[2] = normalized_blue;

  // Run inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed");
    return;
  }

  // Process the output tensor to get the classification result
  int max_index = -1;
  float max_value = -1.0f;

  for (int i = 0; i < output->dims->data[1]; ++i) {
    if (output->data.uint8[i] > max_value) {
      max_value = output->data.uint8[i];
      max_index = i;
    }
  }

  // Print the classification result to serial
  switch (max_index) {
    case 0:
      Serial.println("Apple \uF8FF");  // Apple with Unicode emoji
