      Serial.println("Banana \uD83C\uDF4C");  // Banana with Unicode emoji
      break;
    case 2:
      Serial.println("Orange \uD83C\uDF4A");  // Orange with Unicode emoji
      break;
    default:
      Serial.println("Unknown");
      break;
  }

  delay(1000);  // Delay for 1 second before the next reading
}
