void setup() {
  Serial.begin(9600);

  // Load the model
  model = tflite::GetModel(g_model);  // Ensure g_model is defined in model.h

  if (model->version() != TFLITE_SCHEMA_VERSION) {
    error_reporter->Report("Model schema version does not match interpreter!");
    return;
  }

  // Instantiate the interpreter
  TfLiteStatus allocate_status = interpreter.AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed");
    return;
  }

  // Initialize the APDS9960 sensor
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS9960 sensor!");
    while (1);
  }

  // Enable color sensor
  apds.enableColor(true);

  // Set integration time and gain
  apds.setIntegrationTime(APDS9960_INTEGRATIONTIME_700MS);
  apds.setColorGain(APDS9960_GAIN_1X);
}

void loop() {
  if (apds.colorDataReady()) {  // Check if color data is ready to be read
    uint16_t r, g, b, c;
    apds.getColorData(&r, &g, &b, &c);

    // Normalize the color values to a range between 0 and 1
    float sum = (float)(r + g + b);
    float red = r / sum;
    float green = g / sum;
    float blue = b / sum;

    // Get pointer to input tensor
    TfLiteTensor* input = interpreter.input(0);

    // Copy the processed data into the model's input tensor buffer
    input->data.f[0] = red;
    input->data.f[1] = green;
    input->data.f[2] = blue;

    // Run the inference
    TfLiteStatus invoke_status = interpreter.Invoke();
    if (invoke_status != kTfLiteOk) {
      error_reporter->Report("Invoke failed!");
      return;
    }

    // Get pointer to output tensor
    TfLiteTensor* output = interpreter.output(0);

    // Process the output
    int class_index = -1;
    float max_score = 0.0;
