```cpp
#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include <TensorFlowLite.h>
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "model.h"  // Ensure this path matches your model header file

// Create an instance of the error reporter
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Define a buffer to hold the model data
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version (%d) does not match expected version (%d).\n",
                         model->version(), TFLITE_SCHEMA_VERSION);
}

// Create an instance of the operator resolver
tflite::AllOpsResolver resolver;

// Define the memory buffer for the tensor arena
constexpr int kTensorArenaSize = 2048;
uint8_t tensor_arena[kTensorArenaSize];

// Create and allocate the interpreter
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

// Allocate tensors
TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed\n");
}

// Get pointers to the model's input and output tensors
TfLiteTensor* input = interpreter.input(0);
TfLiteTensor* output = interpreter.output(0);

// Initialize APDS9960 sensor
Adafruit_APDS9960 apds;

void setup() {
  Serial.begin(9600);

  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS9960 sensor!");
    while (1);
  }

  // Enable color sensing with interrupt on data ready
  apds.enableColor(true);
}

void loop() {
  uint16_t r, g, b, c;
  if (!apds.colorAvailable()) {
    delay(50);
    return;
  }

  apds.getColorData(&r, &g, &b, &c);

  // Convert raw color values to normalized floats (0-1 range)
  float red = static_cast<float>(r) / c;
  float green = static_cast<float>(g) / c;
  float blue = static_cast<float>(b) / c;

  // Copy the input data to the model's input tensor
  input->data.f[0] = red;
  input->data.f[1] = green;
  input->data.f[2] = blue;

  // Run inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    return;
  }

  // Process the output tensor
  uint8_t predicted_class = output->data.uint8[0];
  const char* object_name;

  switch (predicted_class) {
    case 0:
      object_name = "Apple";
      break;
    case 1:
      object_name = "Banana";
      break;
    case 2:
      object_name = "Orange";
      break;
    default:
      object_name = "Unknown";
      break;
  }

  // Output the predicted class to Serial
  if (predicted_class == 0) {
    Serial.println("Apple 🍏");
  } else if (predicted_class == 1) {
    Serial.println("Banana 🍌");
  } else if (predicted_class == 2) {
    Serial.println("Orange 🍊");
  }
}
